import { type ScriptContext } from "@threenative/script-stdlib";

type CollectorState = {
  collected: boolean[];
  score: number;
  won: boolean;
};

export function movePlayerToGoal(context: ScriptContext): void {
  const player = context.entity("player");
  if (player === undefined) {
    return;
  }

  const transform = player.transform();
  const position = transform.position;
  const moveX = context.input.getAxis("move-x");
  const moveZ = context.input.getAxis("move-z");
  const length = Math.sqrt(moveX * moveX + moveZ * moveZ);
  const normal = length > 1 ? 1 / length : 1;
  const step = 4 * context.time.fixedDelta;
  const nextX = Math.max(-5.35, Math.min(5.35, position[0] + moveX * normal * step));
  const nextZ = Math.max(-3.85, Math.min(3.85, position[2] + moveZ * normal * step));
  transform.position = [nextX, position[1], nextZ];
}

export function updateCollector(context: ScriptContext): void {
  const pickupIds = ["pickup-1", "pickup-2", "pickup-3", "pickup-4", "pickup-5"];
  const pickupPositions: Array<readonly [number, number, number]> = [
    [-4, 0.32, -2.5],
    [-1.8, 0.32, 2.4],
    [0.4, 0.32, -3.1],
    [2.7, 0.32, 2.1],
    [4.4, 0.32, -1.8],
  ];

  const player = context.entity("player");
  if (player === undefined) {
    return;
  }

  const state = context.state<CollectorState>("CollectorState", {
    collected: [false, false, false, false, false],
    score: 0,
    won: false,
  });

  if (context.input.getButtonDown("retry") || context.input.action("retry")) {
    state.collected = [false, false, false, false, false];
    state.score = 0;
    state.won = false;
    player.transform().position = [0, 0.5, 0];

    for (let index = 0; index < pickupIds.length; index += 1) {
      const pickup = context.entity(pickupIds[index]);
      if (pickup !== undefined) {
        pickup.patch("MeshRenderer", { visible: true });
        pickup.transform().position = pickupPositions[index];
      }
    }
  }

  const playerTransform = player.transform();
  const position = playerTransform.position;

  if (!state.won) {
    const moveX = context.input.getAxis("move-x");
    const moveZ = context.input.getAxis("move-z");
    const length = Math.sqrt(moveX * moveX + moveZ * moveZ);
    const normal = length > 1 ? 1 / length : 1;
    const step = 4 * context.time.fixedDelta;
    const nextX = Math.max(-5.35, Math.min(5.35, position[0] + moveX * normal * step));
    const nextZ = Math.max(-3.85, Math.min(3.85, position[2] + moveZ * normal * step));
    playerTransform.position = [nextX, position[1], nextZ];
  }

  const latestPosition = playerTransform.position;
  for (let index = 0; index < pickupIds.length; index += 1) {
    if (state.collected[index]) {
      continue;
    }
    const pickup = context.entity(pickupIds[index]);
    if (pickup === undefined) {
      continue;
    }
    const pickupPosition = pickup.transform().position;
    const dx = latestPosition[0] - pickupPosition[0];
    const dz = latestPosition[2] - pickupPosition[2];
    if (dx * dx + dz * dz <= 0.75 * 0.75) {
      state.collected[index] = true;
      state.score += 1;
      pickup.patch("MeshRenderer", { visible: false });
      pickup.transform().position = [pickupPosition[0], -10, pickupPosition[2]];
    }
  }

  if (state.score >= pickupIds.length) {
    state.won = true;
  }

  context.resources.set("GameState", {
    collected: state.score,
    scoreText: `Score ${state.score} / ${pickupIds.length}`,
    statusText: state.won ? "You win! All pickups collected." : "Collect all five pickups",
    retryText: state.won ? "Press R or Enter to retry" : "WASD or arrows to move. Press R to retry.",
    total: pickupIds.length,
    won: state.won,
  });
}

